VALUES
  ('aboriginal-64311456-moex-00347', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '依據司法院大法官解釋，立法上運用不確定法律概念者，苟其意義非難以理解，且為受規範者所得預 見，並可經由司法審查加以確認，即不得謂與下列何種原則相違？ 合義務裁量原則  比例原則  信賴保護原則  法律明確性原則', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00348', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何者非屬不當聯結禁止原則之內涵？ 行政處分之附款應與該處分之目的具有正當合理之關聯 雙務行政契約中，人民之給付與行政機關之給付應相當，並具有正當合理之關聯 行政機關為裁量時，不得考量無合理關聯之因素 行政機關對相對人為行政指導時，應明示行政指導之目的、內容及負責指導者等事項', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00349', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於依法行政原則之敘述，下列何者正確？ 行政處分違反法律優位原則，一律當然無效 法律優位原則係指行政行為須有法律上之依據 法律保留原則涉及行政與立法間的權力分配關係 法律保留事項僅得以法律規定，而不得授權以法規命令規定', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00350', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何者屬於私經濟行政？ 警察之巡邏    衛生局之食品衛生檢查 行政機關驗收採購之電腦設備  居家檢疫措施', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00351', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於學生權益保護，依司法院解釋之意旨，下列敘述何者正確？ 公立高中禁止學生成立特定社團，學生除於校內提起申訴外，不得提起任何行政爭訟 國中對學生之管教如屬輕微之干預，不構成權利之侵害 私立高中學生對於學校所為勒令退學之決定不服時，不得提起行政爭訟，應提起民事訴訟 國小教師對學生所為之教育或管理措施，影響學童身心健康，法院得全面審查合法性', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00352', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '甲直轄市空污問題嚴重，擬採取若干措施，下列何者為地方制度法所容許？ 就違反空氣污染防制法之情節嚴重行為，得依其制定之自治條例，於罰則規定刑事處罰 為處理橫跨其他縣市行政轄區之自治事務，得與其他鄰近縣市訂定協議或締結行政契約 就地方自治事項之事務制定自治條例，於罰則規定準用中央法規，處超過10萬元之罰鍰 因空污問題嚴重危害公益，甲市得請求中央主管機關於情況急迫時，逕予介入代行處理', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00353', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '有關行政法人的敘述，下列何者正確？ 地方自治團體得依地方自治條例設立行政法人 原農田水利會依法改制後，已經成為行政法人 依行政選擇自由理論，行政法人得為私法性質 僅能就不具公權力性質之行政事務享有管轄權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00354', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何者屬於管轄權競合？ 經濟部國際貿易局委託臺灣鋼鐵工業同業公會簽發原產地證明書 行政院農業委員會指示地方農會協助認定農作物原產地 私立大學經主管教育行政機關依法授權核發學位證書 行為人設立網際網站，違反個人資料保護法，各地方政府相關主管機關享有管轄權', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00355', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '行政機關執行職務時，下列何種情形不得請求協助？ 彰化縣政府就其自治事項，請求內政部移民署協助 臺北市政府就其自治事項，請求新北市政府協助 衛生福利部就其交付高雄市之委辦事項，請求高雄市政府協助 雲林縣政府就中央交付之委辦事項，請求嘉義縣政府協助', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00356', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於司法院大法官釋字第785號解釋之敘述，下列何者正確？ 公務人員基於與國家公法上之職務關係，其作為基本權利主體之身分即與一般人民有所不同 公務人員保障法關於申訴、再申訴之規定，並不排除公務人員得再依法提起相應之行政訴訟之可能， 與憲法訴訟權之保障意旨相違 公務人員保障法第23條規定未就業務性質特殊機關所屬公務人員之超勤補償等事項，設定必要合 理之框架性規範而屬違憲 公務員服務法第11條第2項及公務人員週休二日實施辦法第4條第1項等規定，已就業務性質特 殊機關所屬公務人員勤休方式予以明確規定而屬合憲', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
